```python
def largest_smallest_integers(lst):
    """
    Returns a tuple (a, b) where 'a' is the largest negative integer and 'b' is the smallest positive integer.
    If no negative integers exist, a is None. If no positive integers exist, b is None.

    Args:
        lst: List of numbers

    Returns:
        tuple: (largest_negative, smallest_positive)
    """
    largest_negative = None
    smallest_positive = None

    for num in lst:
        # Check for negative integers
        if isinstance(num, int) and num < 0:
            if largest_negative is None or num > largest_negative:
                largest_negative = num

        # Check for positive integers
        elif isinstance(num, int) and num > 0:
            if smallest_positive is None or num < smallest_positive:
                smallest_positive = num

    return (largest_negative, smallest_positive)
```

```python
def valid_date(dste):
    # Rule 1: The date string is not empty
    if not dste:
        return False

    # Check if the format is mm-dd-yyyy (exactly 10 characters with dashes at positions 2 and 5)
    if len(dste) != 10 or dste[2] != '-' or dste[5] != '-':
        return False

    # Split the string by dashes
    parts = dste.split('-')
    if len(parts) != 3:
        return False

    mm_str, dd_str, yyyy_str = parts

    # Check if all parts are numeric
    if not (mm_str.isdigit() and dd_str.isdigit() and yyyy_str.isdigit()):
        return False

    # Convert to integers
    try:
        mm = int(mm_str)
        dd = int(dd_str)
        yyyy = int(yyyy_str)
    except ValueError:
        return False

    # Rule 3: Months should be between 1 and 12
    if mm < 1 or mm > 12:
        return False

    # Rule 2: Validate days based on month
    if mm in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if dd < 1 or dd > 31:
            return False
    elif mm in [4, 6, 9, 11]:
        # Months with 30 days
        if dd < 1 or dd > 30:
            return False
    elif mm == 2:
        # February - up to 29 days (as per problem statement, no leap year check needed)
        if dd < 1 or dd > 29:
            return False

    # Additional check: ensure proper zero-padding for mm and dd (2 digits each)
    # The format requires mm-dd-yyyy, so mm and dd should be 2 digits
    if len(mm_str) != 2 or len(dd_str) != 2 or len(yyyy_str) != 4:
        return False

    return True
```

