    # Check if the format is mm-dd-yyyy (exactly 10 characters with dashes at positions 2 and 5)
    if len(dste) != 10 or dste[2] != '-' or dste[5] != '-':
        return False

    # Split the string by dashes
    parts = dste.split('-')
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    # Check if all parts are numeric
    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(month_str)
        day = int(day_str)
        year = int(year_str)
    except ValueError:
        return False

    # Rule 3: Months should be between 1 and 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Check days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # 31 days months
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # 30 days months
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - up to 29 days (we're not checking leap years per problem statement)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure proper zero-padding (though not explicitly required, 
    # the examples suggest mm-dd-yyyy format with leading zeros)
    # Check if month and day have exactly 2 digits (since format is mm-dd-yyyy)
    if len(month_str) != 2 or len(day_str) != 2 or len(year_str) != 4:
        return False

    return True
