```python
def valid_date(dste):
    # Rule 1: The date string is not empty
    if not dste:
        return False

    # Check if the format is mm-dd-yyyy (exactly 10 characters with dashes at positions 2 and 5)
    if len(dste) != 10 or dste[2] != '-' or dste[5] != '-':
        return False

    # Split the string by dashes
    parts = dste.split('-')
    if len(parts) != 3:
        return False

    # Try to convert parts to integers
    try:
        month = int(parts[0])
        day = int(parts[1])
        year = int(parts[2])
    except ValueError:
        return False

    # Rule 3: The months should not be less than 1 or higher than 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Months with 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - up to 29 days (simplified validation as per problem statement)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure each part has correct number of digits (mm-dd-yyyy format)
    # Month should be 1 or 2 digits, but since we have dashes at positions 2 and 5, 
    # parts[0] should be 1 or 2 chars, parts[1] should be 1 or 2 chars, parts[2] should be 4 chars
    if len(parts[0]) > 2 or len(parts[1]) > 2 or len(parts[2]) != 4:
        return False

    # Also check for leading zeros consistency - but the examples show '03', '06', etc. are valid
    # So we just need to ensure no empty parts
    if not parts[0] or not parts[1] or not parts[2]:
        return False

    return True
```

```python
def closest_integer(value):
    """
    Takes a string representing a number and returns the closest integer.
    If the number is equidistant from two integers, rounds away from zero.

    Args:
        value (str): A string representing a number

    Returns:
        int: The closest integer, with ties rounded away from zero
    """
    num = float(value)

    # Get the floor and ceiling values
    import math
    floor_val = math.floor(num)
    ceil_val = math.ceil(num)

    # Calculate distances to floor and ceiling
    dist_to_floor = abs(num - floor_val)
    dist_to_ceil = abs(num - ceil_val)

    # If equidistant, round away from zero
    if dist_to_floor == dist_to_ceil:
        if num >= 0:
            return int(ceil_val)
        else:
            return int(floor_val)
    # Otherwise, return the closer one
    elif dist_to_floor < dist_to_ceil:
        return int(floor_val)
    else:
        return int(ceil_val)
```

```python
def closest_integer(value):
    """
    Takes a string representing a number and returns the closest integer.
    If equidistant from two integers, rounds away from zero.

    Args:
        value (str): String representation of a number

    Returns:
        int: The closest integer, with ties rounded away from zero
    """
    num = float(value)

    # Get the floor and ceiling values
    import math
    floor_val = math.floor(num)
    ceil_val = math.ceil(num)

    # Check if num is already an integer
    if num == int(num):
        return int(num)

    # Calculate distances to floor and ceiling
    dist_to_floor = abs(num - floor_val)
    dist_to_ceil = abs(num - ceil_val)

    # If equidistant, round away from zero
    if dist_to_floor == dist_to_ceil:
        if num > 0:
            return int(ceil_val)
        else:
            return int(floor_val)
    # Otherwise, return the closer one
    elif dist_to_floor < dist_to_ceil:
        return int(floor_val)
    else:
        return int(ceil_val)
```

```python
def is_bored(S):
    if not S:
        return 0

    # Split the string into sentences using '.', '?', and '!' as delimiters
    # We'll split on each punctuation mark and keep track of sentence boundaries
    sentences = []
    current_sentence = ""

    for char in S:
        if char in '.!?':
            # Add the current sentence (stripped of whitespace) to our list
            if current_sentence.strip():
                sentences.append(current_sentence.strip())
            current_sentence = ""
        else:
            current_sentence += char

    # Don't forget the last sentence if the string doesn't end with punctuation
    if current_sentence.strip():
        sentences.append(current_sentence.strip())

    # Count sentences that start with "I " or are exactly "I"
    count = 0
    for sentence in sentences:
        # Strip leading whitespace and check if it starts with "I "
        # Also handle case where sentence is just "I"
        stripped = sentence.strip()
        if stripped.startswith("I ") or stripped == "I":
            count += 1

    return count
```

```python
def is_sorted(lst):
    # Handle empty list or single element
    if len(lst) <= 1:
        return True

    # Check for duplicates - count occurrences of each number
    from collections import Counter
    counts = Counter(lst)
    if any(count > 2 for count in counts.values()):
        return False

    # Check if list is sorted in ascending order
    for i in range(1, len(lst)):
        if lst[i] < lst[i-1]:
            return False

    return True
```

