```python
def find_max(words):
    if not words:
        return ""

    # Calculate unique character count for each word
    unique_counts = []
    for word in words:
        unique_count = len(set(word))
        unique_counts.append(unique_count)

    # Find the maximum number of unique characters
    max_unique_count = max(unique_counts)

    # Find all words with maximum unique character count
    candidates = []
    for i, count in enumerate(unique_counts):
        if count == max_unique_count:
            candidates.append(words[i])

    # Return the lexicographically smallest among candidates
    return min(candidates)
```

```python
def fib4(n: int) -> int:
    if n == 0:
        return 0
    elif n == 1:
        return 0
    elif n == 2:
        return 2
    elif n == 3:
        return 0

    # Initialize the first four values
    a, b, c, d = 0, 0, 2, 0  # fib4(0), fib4(1), fib4(2), fib4(3)

    # Iterate from 4 to n
    for i in range(4, n + 1):
        next_val = a + b + c + d
        # Shift all values: a becomes b, b becomes c, c becomes d, d becomes next_val
        a, b, c, d = b, c, d, next_val

    return d
```

