def solve(s):
    # Check if the string contains any letters
    has_letter = any(c.isalpha() for c in s)

    if has_letter:
        # If there's at least one letter, reverse case of letters, keep others unchanged
        result = []
        for c in s:
            if c.isalpha():
                if c.islower():
                    result.append(c.upper())
                else:
                    result.append(c.lower())
            else:
