```python
def even_odd_count(num):
    # Convert to absolute value to handle negative numbers
    num = abs(num)

    # Handle the case where num is 0
    if num == 0:
        return (1, 0)

    even_count = 0
    odd_count = 0

    # Extract each digit and count even/odd
    while num > 0:
        digit = num % 10
        if digit % 2 == 0:
            even_count += 1
        else:
            odd_count += 1
        num //= 10

    return (even_count, odd_count)
```

```python
def even_odd_count(num):
    # Convert to string and remove negative sign if present
    num_str = str(abs(num))

    even_count = 0
    odd_count = 0

    # Count even and odd digits
    for digit_char in num_str:
        digit = int(digit_char)
        if digit % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    return (even_count, odd_count)
```

