def cycpattern_check(a, b):
    # If b is empty, it's always a substring
    if not b:
        return True

    # Generate all rotations of b
    rotations = []
    for i in range(len(b)):
        rotation = b[i:] + b[:i]
        rotations.append(rotation)

    # Check if any rotation is a substring of a
    for rotation in rotations:
        if rotation in a:
            return True

    return False
