```python
def is_simple_power(x, n):
    """
    Returns True if x is a simple power of n, i.e., if there exists an integer k 
    such that n**k == x. Returns False otherwise.

    Args:
        x: The number to check
        n: The base number

    Returns:
        bool: True if x is a simple power of n, False otherwise
    """
    # Handle edge cases
    if x == 1:
        # 1 is n^0 for any n != 0, but we need to be careful with n = 0 or n = 1
        if n == 0:
            return False  # 0^k is 0 for k > 0, and 0^0 is undefined
        if n == 1:
            return True   # 1^k = 1 for any k
        return True       # n^0 = 1 for any n != 0

    if n == 0:
        return x == 0     # 0^k = 0 for k > 0, but 0^0 is undefined

    if n == 1:
        return x == 1     # 1^k = 1 for any k

    if n == -1:
        return x == 1 or x == -1  # (-1)^k is 1 for even k, -1 for odd k

    # For positive n > 1
    if n > 1:
        if x < 1:
            return False
        power = 1
        while power < x:
            power *= n
        return power == x

    # For negative n < -1
    if n < -1:
        if x == 0:
            return False
        power = 1
        k = 0
        while abs(power) <= abs(x):
            if power == x:
                return True
            power *= n
            k += 1
        return False

    # For 0 < n < 1 (fractional base)
    if 0 < n < 1:
        if x > 1:
            return False
        if x <= 0:
            return False
        power = 1
        while power > x:
            power *= n
            if power == x:
                return True
        return False

    return False
```

```python
def flip_case(string: str) -> str:
    """
    Flip lowercase characters to uppercase and uppercase to lowercase.

    Args:
        string: The input string to process

    Returns:
        A new string with case flipped for each alphabetic character
    """
    result = []
    for char in string:
        if char.islower():
            result.append(char.upper())
        elif char.isupper():
            result.append(char.lower())
        else:
            result.append(char)  # Keep non-alphabetic characters unchanged
    return ''.join(result)
```

