def split_words(txt):
    # Check if there are whitespaces
    if ' ' in txt:
        return txt.split()

    # Check if there are commas
    elif ',' in txt:
        return txt.split(',')

    # If no whitespaces and no commas, count lowercase letters with odd order
    else:
        count = 0
        for char in txt:
            if char.islower() and 'a' <= char <= 'z':
                # ord(char) - ord('a') gives the position (0-indexed)
                # We want odd positions: 1, 3, 5, ... which correspond to 'b', 'd', 'f', etc.
                if (ord(char) - ord('a')) % 2 == 1:
                    count += 1
        return count
```

