def split_words(txt):
    # Check if there are whitespaces
    if ' ' in txt:
        return txt.split()

    # Check if there are commas
    elif ',' in txt:
        return txt.split(',')

    # Otherwise, count lowercase letters with odd order in alphabet
    # ord('a') = 97, but the problem states ord('a') = 0, so we need to use (ord(c) - ord('a'))
    count = 0
    for c in txt:
        if c.islower() and 'a' <= c <= 'z':
            # Calculate position: 'a' -> 0, 'b' -> 1, ..., 'z' -> 25
            position = ord(c) - ord('a')
            if position % 2 == 1:  # odd position
                count += 1

    return count
