def derivative(xs: list) -> list:
    if len(xs) <= 1:
        return []

    result = []
    for i in range(1, len(xs)):
        result.append(i * xs[i])

    return result
```

```python
def encode(message):
    vowels = 'aeiouAEIOU'
    vowel_map = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    result = []
    for char in message:
        if char.isalpha():
            # Swap case
            swapped_char = char.lower() if char.isupper() else char.upper()

            # Replace vowels with letter 2 places ahead
            if swapped_char in vowel_map:
                result.append(vowel_map[swapped_char])
            else:
                result.append(swapped_char)
        else:
            # Keep non-alphabetic characters as is (though problem says assume only letters)
            result.append(char)

    return ''.join(result)
```

